
import React, { useRef } from "react";
import { Upload, Camera, ImageIcon } from "lucide-react";
import { Button } from "@/components/ui/button";

interface UploadInterfaceProps {
  onFileSelect: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onCameraStart: () => void;
}

const UploadInterface: React.FC<UploadInterfaceProps> = ({ 
  onFileSelect, 
  onCameraStart 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  return (
    <div className="text-center p-6">
      <div className="mx-auto h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center mb-4">
        <ImageIcon className="h-6 w-6 text-primary" />
      </div>
      <h3 className="text-lg font-medium mb-1">Upload Waste Image</h3>
      <p className="text-sm text-muted-foreground mb-4">
        Drag and drop or use camera
      </p>
      <div className="flex flex-col sm:flex-row gap-2 justify-center">
        <Button
          variant="outline"
          className="group relative overflow-hidden"
          onClick={() => fileInputRef.current?.click()}
        >
          <span className="relative z-10 flex items-center gap-1">
            <Upload className="h-4 w-4" /> Select Image
          </span>
          <span className="absolute inset-0 bg-primary/10 transform -translate-x-full group-hover:translate-x-0 transition-transform duration-300" />
        </Button>
        <Button
          variant="outline"
          className="group relative overflow-hidden"
          onClick={onCameraStart}
        >
          <span className="relative z-10 flex items-center gap-1">
            <Camera className="h-4 w-4" /> Use Camera
          </span>
          <span className="absolute inset-0 bg-primary/10 transform -translate-x-full group-hover:translate-x-0 transition-transform duration-300" />
        </Button>
      </div>
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        onChange={onFileSelect}
        className="hidden"
      />
    </div>
  );
};

export default UploadInterface;
